// جلب النص من العقدة السابقة (تأكد من تغيير اسم الحقل إذا كان مختلفاً عن 'text')
const resumeText = $input.first().json.text || "";

// مصفوفة الكلمات المطلوب البحث عنها
const requiredKeywords = ['experience', 'skills', 'education'];

// 1. التحقق من الطول (أكبر من 100 حرف)
const isLongEnough = resumeText.length > 100;

// 2. التحقق من وجود الكلمات الثلاث (مع تجاهل حالة الأحرف Case Insensitive)
const lowerText = resumeText.toLowerCase();
const hasAllKeywords = requiredKeywords.every(word => lowerText.includes(word.toLowerCase()));

// النتيجة النهائية: يجب أن يتحقق الشرطان معاً
return {
  isValid: isLongEnough && hasAllKeywords,
  details: {
    characterCount: resumeText.length,
    foundKeywords: hasAllKeywords
  }
};

// 1. جلب البيانات من العقدة السابقة (تأكد من المسار الصحيح)
const yearsOfExperience = $json.output?.Years_of_Experience || 0;
const skills = $json.output?.Skills || "";

// 2. التحقق من الشروط
// الشرط الأول: سنوات الخبرة أكبر من أو تساوي 2
const hasEnoughExperience = yearsOfExperience >= 2;

// الشرط الثاني: المهارات تحتوي على SQL (مع تجاهل حالة الأحرف)
const hasSqlSkill = skills.toLowerCase().includes('sql');

// النتيجة النهائية
return {
  isQualified: hasEnoughExperience && hasSqlSkill,
  details: {
    yearsFound: yearsOfExperience,
    hasSql: hasSqlSkill,
    originalSkills: skills
  }
};

// الوصول إلى القائمة من نود Aggregate
const list = items[0].json.data;

// 1. ترتيب القائمة من الأعلى سكور إلى الأقل
list.sort((a, b) => b.Score - a.Score);

// 2. تحويل الرقم العشري (0.85) إلى نص مئوي (85%) لكل عنصر في القائمة
const formattedList = list.map(item => {
  return {
    ...item,
    Score: (item.Score * 100).toFixed(0) + '%'
  };
});

return [{
  json: {
    shortlist_table: formattedList
  }
}];
